import React, { useState, useCallback, useEffect } from 'react';
import {
    FormControl,
    InputLabel,
    OutlinedInput,
    InputAdornment,
    IconButton
} from '@mui/material';
import MicIcon from '@mui/icons-material/Mic';
import MicOffIcon from '@mui/icons-material/MicOff';

export const useVoiceInput = () => {
    const [isListening, setIsListening] = useState(false);
    const [transcript, setTranscript] = useState('');
    
    const startListening = useCallback(() => {
        if ('webkitSpeechRecognition' in window) {
            const recognition = new window.webkitSpeechRecognition();
            recognition.continuous = false;
            recognition.interimResults = true;

            recognition.onstart = () => {
                setIsListening(true);
            };

            recognition.onresult = (event) => {
                const transcript = Array.from(event.results)
                    .map(result => result[0])
                    .map(result => result.transcript)
                    .join('');
                setTranscript(transcript);
            };

            recognition.onerror = (event) => {
                console.error('Speech recognition error', event.error);
                setIsListening(false);
            };

            recognition.onend = () => {
                setIsListening(false);
            };

            recognition.start();
        } else {
            alert('Speech recognition is not supported in this browser. Please use Chrome.');
        }
    }, []);

    const stopListening = useCallback(() => {
        setIsListening(false);
        if ('webkitSpeechRecognition' in window) {
            window.webkitSpeechRecognition.stop();
        }
    }, []);

    const resetTranscript = useCallback(() => {
        setTranscript('');
    }, []);

    return {
        isListening,
        transcript,
        startListening,
        stopListening,
        resetTranscript
    };
};

// Create a voice-enabled text input component
export const VoiceInput = ({ label, value, onChange, multiline = false, rows = 1 }) => {
    const { isListening, transcript, startListening, stopListening, resetTranscript } = useVoiceInput();
    const [internalValue, setInternalValue] = useState(value || '');

    const handleVoiceInput = useCallback(() => {
        if (isListening) {
            stopListening();
        } else {
            startListening();
        }
    }, [isListening, startListening, stopListening]);

    useEffect(() => {
        if (transcript) {
            const newValue = internalValue + ' ' + transcript;
            setInternalValue(newValue);
            onChange(newValue);
            resetTranscript();
        }
    }, [transcript, internalValue, onChange, resetTranscript]);

    const handleTextInput = (e) => {
        setInternalValue(e.target.value);
        onChange(e.target.value);
    };

    return (
        <FormControl fullWidth variant="outlined" margin="normal">
            <InputLabel>{label}</InputLabel>
            <OutlinedInput
                value={internalValue}
                onChange={handleTextInput}
                multiline={multiline}
                rows={rows}
                endAdornment={
                    <InputAdornment position="end">
                        <IconButton
                            onClick={handleVoiceInput}
                            edge="end"
                        >
                            {isListening ? <MicOffIcon color="error" /> : <MicIcon />}
                        </IconButton>
                    </InputAdornment>
                }
                label={label}
            />
        </FormControl>
    );
};
